import{c as e,Q as i,j as l,m as s}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"Android keystore、AAB、APK 与签名轮换","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/05-Android-keystore-AAB-APK与签名轮换.md","filePath":"mobileCommonLearning/05-Android-keystore-AAB-APK与签名轮换.md","lastUpdated":1780912084000}'),n={name:"mobileCommonLearning/05-Android-keystore-AAB-APK与签名轮换.md"};function t(p,a,o,d,r,h){return i(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="android-keystore、aab、apk-与签名轮换" tabindex="-1">Android keystore、AAB、APK 与签名轮换 <a class="header-anchor" href="#android-keystore、aab、apk-与签名轮换" aria-label="Permalink to &quot;Android keystore、AAB、APK 与签名轮换&quot;">​</a></h1><p>Android 发布最怕两件事:签名丢了,签名泄漏了。</p><p>一句话先记住:<strong>Android 更新链路强依赖签名兼容,release keystore 是生产资产,不是本地配置文件。</strong></p><hr><h2 id="一、apk-和-aab" tabindex="-1">一、APK 和 AAB <a class="header-anchor" href="#一、apk-和-aab" aria-label="Permalink to &quot;一、APK 和 AAB&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产物</th><th>说明</th></tr></thead><tbody><tr><td>APK</td><td>可直接安装,官网和部分渠道常用</td></tr><tr><td>AAB</td><td>Android App Bundle,上传 Google Play 后由商店生成 APK</td></tr></tbody></table><p>AAB 的好处:</p><ul><li>按设备拆分 ABI、语言、屏幕密度</li><li>用户下载更小</li><li>Play Console 发布主流路径</li></ul><p>但国内渠道和官网分发仍然经常需要 APK。</p><hr><h2 id="二、签名类型" tabindex="-1">二、签名类型 <a class="header-anchor" href="#二、签名类型" aria-label="Permalink to &quot;二、签名类型&quot;">​</a></h2><p>Android 有多代签名方案:</p><table tabindex="0"><thead><tr><th>Scheme</th><th>说明</th></tr></thead><tbody><tr><td>v1</td><td>JAR signing,老系统兼容</td></tr><tr><td>v2</td><td>APK 全文件签名,Android 7+</td></tr><tr><td>v3</td><td>支持签名轮换 lineage,Android 9+</td></tr><tr><td>v4</td><td>增量安装相关</td></tr></tbody></table><p>现代 release 包通常会同时包含多个 scheme,由构建工具处理。</p><p>你不需要手写这些,但要知道:<strong>签名轮换依赖 v3 lineage,不是换个 keystore 直接发。</strong></p><hr><h2 id="三、google-play-app-signing" tabindex="-1">三、Google Play App Signing <a class="header-anchor" href="#三、google-play-app-signing" aria-label="Permalink to &quot;三、Google Play App Signing&quot;">​</a></h2><p>Google Play 有两类 key:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App signing key   真正给用户安装包签名,Google 托管</span></span>
<span class="line"><span>Upload key        你上传 AAB 时使用,可重置</span></span></code></pre></div><p>如果丢的是 upload key:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>可以走 Play Console 重置上传密钥</span></span>
<span class="line"><span>不影响用户更新</span></span></code></pre></div><p>如果自己管理 app signing key 且丢失:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>无法从证书 / APK 还原私钥</span></span>
<span class="line"><span>通常无法无缝更新</span></span></code></pre></div><p>新项目优先使用 Play App Signing。</p><hr><h2 id="四、国内渠道的现实" tabindex="-1">四、国内渠道的现实 <a class="header-anchor" href="#四、国内渠道的现实" aria-label="Permalink to &quot;四、国内渠道的现实&quot;">​</a></h2><p>国内没有统一托管兜底。</p><p>常见渠道:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>华为</span></span>
<span class="line"><span>小米</span></span>
<span class="line"><span>OPPO</span></span>
<span class="line"><span>vivo</span></span>
<span class="line"><span>荣耀</span></span>
<span class="line"><span>应用宝</span></span>
<span class="line"><span>百度</span></span>
<span class="line"><span>360</span></span>
<span class="line"><span>官网 APK</span></span></code></pre></div><p>每个渠道对签名变更的流程、材料、人工审核都不同。不要等 keystore 丢了才去问客服。</p><p>至少提前记录:</p><ul><li>应用名</li><li>包名</li><li>当前线上版本</li><li>原签名 MD5 / SHA1 / SHA256</li><li>新签名 MD5 / SHA1 / SHA256</li><li>软著 / 营业执照 / 授权材料</li><li>各渠道后台账号和负责人</li></ul><hr><h2 id="五、签名轮换" tabindex="-1">五、签名轮换 <a class="header-anchor" href="#五、签名轮换" aria-label="Permalink to &quot;五、签名轮换&quot;">​</a></h2><p>签名泄漏但旧签名仍在手里时,可以评估 signing lineage:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>旧签名 -&gt; 授权新签名</span></span>
<span class="line"><span>新包带完整签名历史</span></span>
<span class="line"><span>系统识别新旧签名连续</span></span></code></pre></div><p>风险:</p><ul><li>Android 9+ 才开始支持 v3 轮换</li><li>老系统不一定识别</li><li>厂商 ROM 和国内渠道需要实测</li><li>三方 SDK 对签名指纹的校验可能不认 lineage</li></ul><p>如果旧签名已经丢失,就无法生成 lineage。</p><hr><h2 id="六、三方平台同步" tabindex="-1">六、三方平台同步 <a class="header-anchor" href="#六、三方平台同步" aria-label="Permalink to &quot;六、三方平台同步&quot;">​</a></h2><p>换签名或轮换后,检查:</p><ul><li>微信开放平台</li><li>支付宝开放平台</li><li>Firebase / Google Sign-In</li><li>华为 AGC</li><li>厂商推送</li><li>地图 SDK</li><li>广告归因</li><li>App Links <code>assetlinks.json</code></li></ul><p>很多平台绑定证书指纹。签名变了,登录、支付、深链可能全部失效。</p><hr><h2 id="七、官网-apk" tabindex="-1">七、官网 APK <a class="header-anchor" href="#七、官网-apk" aria-label="Permalink to &quot;七、官网 APK&quot;">​</a></h2><p>官网 APK 风险更高:</p><ul><li>没有商店托管</li><li>用户可能从旧链接下载</li><li>CDN / 下载页可能被替换</li><li>签名泄漏后攻击者可伪造同包名更新包</li></ul><p>官网分发必须做:</p><ul><li>HTTPS</li><li>文件 hash</li><li>下载包签名校验说明</li><li>版本号校验</li><li>后端拦截异常版本 / 异常签名指纹</li></ul><hr><h2 id="八、什么时候会出事故" tabindex="-1">八、什么时候会出事故 <a class="header-anchor" href="#八、什么时候会出事故" aria-label="Permalink to &quot;八、什么时候会出事故&quot;">​</a></h2><ol><li>keystore 只在一个人电脑上。</li><li>密码写在聊天记录里。</li><li>换签名后国内渠道拒绝覆盖。</li><li>签名泄漏后攻击者伪造升级包。</li><li>App Links 没更新 SHA-256 指纹。</li><li>轮换签名只测 Android 13,没测 Android 8 用户。</li></ol><hr><h2 id="九、检查清单" tabindex="-1">九、检查清单 <a class="header-anchor" href="#九、检查清单" aria-label="Permalink to &quot;九、检查清单&quot;">​</a></h2><ul><li>[ ] 是否使用 Play App Signing</li><li>[ ] upload key 是否可重置</li><li>[ ] release keystore 是否至少两份加密备份</li><li>[ ] 签名指纹是否记录</li><li>[ ] 国内渠道是否有签名变更材料</li><li>[ ] 三方平台是否盘点签名依赖</li><li>[ ] 官网 APK 是否有 hash 和异常版本拦截</li><li>[ ] 签名轮换是否覆盖旧系统和渠道实测</li></ul><hr><h2 id="十、心智模型" tabindex="-1">十、心智模型 <a class="header-anchor" href="#十、心智模型" aria-label="Permalink to &quot;十、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Play App Signing 让 Google 托管发布签名</span></span>
<span class="line"><span>国内渠道需要你自己治理签名资产</span></span>
<span class="line"><span>签名轮换不是换文件,是签名历史链</span></span>
<span class="line"><span>签名变更会牵动所有依赖指纹的平台</span></span></code></pre></div><p>下一篇 06 讲 iOS 证书、私钥、Provisioning Profile 与 Archive。</p>`,60)])])}const A=e(n,[["render",t]]);export{g as __pageData,A as default};
